import { Router } from 'express';
import { createBanner, deleteBanner, getAdminHomeSettings, getAdminSiteSettings, getSocialLinks, listBanners, putAdminHomeSettings, putAdminSiteSettings, putSocialLinks, updateBanner } from '../controllers/adminController.js';
import { requireAdmin } from '../middleware/auth.js';
import newsAdminRoutes from './newsAdminRoutes.js';
const router = Router();
router.use(requireAdmin);
router.get('/settings/site', getAdminSiteSettings);
router.put('/settings/site', putAdminSiteSettings);
router.get('/settings/home', getAdminHomeSettings);
router.put('/settings/home', putAdminHomeSettings);
router.get('/settings/site-settings', getAdminSiteSettings);
router.put('/settings/site-settings', putAdminSiteSettings);
router.get('/settings/home-control', getAdminHomeSettings);
router.put('/settings/home-control', putAdminHomeSettings);
router.get('/settings/social-links', getSocialLinks);
router.put('/settings/social-links', putSocialLinks);
router.get('/banners', listBanners);
router.post('/banners', createBanner);
router.put('/banners/:id', updateBanner);
router.delete('/banners/:id', deleteBanner);
router.use(newsAdminRoutes);
export default router;
